8		"github.com/DocumentDrivenDX/ddx/internal/docgraph"
9		ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
10	)
11	
12	var errNotMetricArtifact = fmt.Errorf("not a metric artifact")
13	
14	type Store struct {
15		WorkingDir string
16		execStore  *ddxexec.Store
17	}
18	
19	func NewStore(workingDir string) *Store {
20		return &Store{
21			WorkingDir: workingDir,
22			execStore:  ddxexec.NewStore(workingDir),
23		}
24	}
25	
26	func (s *Store) Init() error {
27		if s.execStore != nil {
28			return s.execStore.Init()
29		}
30		return nil
31	}
32	
33	func (s *Store) Validate(metricID string) (*Definition, *docgraph.Document, error) {
34		doc, err := s.loadMetricArtifact(metricID)
35		if err != nil {
36			return nil, nil, err
37		}
38		def, err := s.LoadDefinition(metricID)
39		if err != nil {
40			return nil, nil, err
41		}
42		if def.MetricID != metricID {
43			return nil, nil, fmt.Errorf("metric definition %q does not target %q", def.DefinitionID, metricID)
44		}
45		if len(def.Command) == 0 {
46			return nil, nil, fmt.Errorf("metric definition %q has no command", def.DefinitionID)
47		}
48		if def.Comparison == "" {
49			def.Comparison = ComparisonLowerIsBetter
50		}
51		switch def.Comparison {
52		case ComparisonLowerIsBetter, ComparisonHigherIsBetter:
53		default:
54			return nil, nil, fmt.Errorf("metric definition %q has invalid comparison %q", def.DefinitionID, def.Comparison)
55		}
56		return &def, doc, nil
57	}
58	
59	func (s *Store) Run(ctx context.Context, metricID string) (HistoryRecord, error) {
60		def, _, err := s.Validate(metricID)
61		if err != nil {
62			return HistoryRecord{}, err
63		}
64		rec, err := s.execStore.Run(ctx, def.DefinitionID)
65		if err != nil {
66			return HistoryRecord{}, err
67		}
68		return metricHistoryFromExec(rec)
69	}
70	
71	func (s *Store) Compare(metricID, against string) (HistoryRecord, ComparisonResult, error) {
72		history, err := s.History(metricID)
73		if err != nil {
74			return HistoryRecord{}, ComparisonResult{}, err
75		}
76		if len(history) == 0 {
77			return HistoryRecord{}, ComparisonResult{}, fmt.Errorf("no history for metric %q", metricID)
78		}
79		current := history[len(history)-1]
80		target, err := selectComparisonTarget(history, against)
81		if err != nil {
82			return HistoryRecord{}, ComparisonResult{}, err
83		}
84		result := comparisonFor(current.Value, target.Value, current.Comparison.Direction)
85		current.Comparison = result
86		return current, result, nil
87	}
88	
89	func (s *Store) Trend(metricID string) (TrendSummary, error) {
90		history, err := s.History(metricID)
91		if err != nil {
92			return TrendSummary{}, err
93		}
94		if len(history) == 0 {
95			return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
96		}
97		summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: history[len(history)-1].Unit, UpdatedAt: history[len(history)-1].ObservedAt}
98		var sum float64
99		for _, rec := range history {
100			if rec.Value < summary.Min {
101				summary.Min = rec.Value
102			}
103			if rec.Value > summary.Max {
104				summary.Max = rec.Value
105			}
106			sum += rec.Value
107			summary.UpdatedAt = rec.ObservedAt
108			if rec.Unit != "" {
109				summary.Unit = rec.Unit
110			}
111		}
112		summary.Count = len(history)
113		summary.Average = sum / float64(len(history))
114		return summary, nil
115	}
116	
117	func (s *Store) LoadDefinition(metricID string) (Definition, error) {
118		if s.execStore == nil {
119			return Definition{}, fmt.Errorf("metric store is not initialized")
120		}
121		defs, err := s.execStore.ListDefinitions(metricID)
122		if err != nil {
123			return Definition{}, err
124		}
125		var (
126			best  Definition
127			found bool
128		)
129		for _, def := range defs {
130			if def.ID == "" {
131				continue
132			}
133			mapped, err := metricDefinitionFromExec(def)
134			if err != nil {
135				return Definition{}, err
136			}
137			if mapped.MetricID != metricID || !mapped.Active {
138				continue
139			}
140			if !found || mapped.CreatedAt.After(best.CreatedAt) || (mapped.CreatedAt.Equal(best.CreatedAt) && mapped.DefinitionID > best.DefinitionID) {
141				best = mapped
142				found = true
143			}
144		}
145		if !found {
146			return Definition{}, fmt.Errorf("metric definition for %q not found", metricID)
147		}
148		if best.DefinitionID == "" {
149			return Definition{}, fmt.Errorf("metric definition for %q is missing definition_id", metricID)
150		}
151		return best, nil
152	}
153	
154	func (s *Store) SaveDefinition(def Definition) error {
155		if def.DefinitionID == "" {
156			return fmt.Errorf("definition_id is required")
157		}
158		if def.MetricID == "" {
159			return fmt.Errorf("metric_id is required")
160		}
161		if s.execStore == nil {
162			return fmt.Errorf("metric store is not initialized")
163		}
164		return s.execStore.SaveDefinition(metricDefinitionToExec(def))
165	}
166	
167	func (s *Store) AppendHistory(rec HistoryRecord) error {
168		if s.execStore == nil {
169			return fmt.Errorf("metric store is not initialized")
170		}
171		return s.execStore.SaveRunRecord(metricHistoryToRun(rec))
172	}
173	
174	func (s *Store) History(metricID string) ([]HistoryRecord, error) {
175		if s.execStore == nil {
176			return []HistoryRecord{}, fmt.Errorf("metric store is not initialized")
177		}
178		records, err := s.execStore.History(metricID, "")
179		if err != nil {
180			return nil, err
181		}
182		out := make([]HistoryRecord, 0, len(records))
183		for _, rec := range records {
184			mapped, err := metricHistoryFromExec(rec)
185			if err != nil {
186				return nil, err
187			}
188			if mapped.MetricID == metricID {
189				out = append(out, mapped)
190			}
191		}
192		return out, nil
193	}
194	
195	func (s *Store) loadMetricArtifact(metricID string) (*docgraph.Document, error) {
196		if !strings.HasPrefix(metricID, "MET-") {
197			return nil, fmt.Errorf("%w: %s", errNotMetricArtifact, metricID)
198		}
199		graph, err := docgraph.BuildGraph(s.WorkingDir)
200		if err != nil {
201			return nil, err
202		}
203		doc, ok := graph.Show(metricID)
204		if !ok {
205			return nil, fmt.Errorf("metric artifact %q not found", metricID)
206		}
207		return &doc, nil
208	}
209	
210	func selectComparisonTarget(history []HistoryRecord, against string) (HistoryRecord, error) {
211		switch against {
212		case "", "latest":
213			return history[len(history)-1], nil
214		case "baseline":
215			return history[0], nil
216		default:
217			for _, rec := range history {
218				if rec.RunID == against {
219					return rec, nil
220				}
221			}
222			return HistoryRecord{}, fmt.Errorf("comparison target %q not found", against)
223		}
224	}
225	
226	func comparisonFor(current, baseline float64, direction string) ComparisonResult {
227		delta := current - baseline
228		if direction == ComparisonHigherIsBetter {
229			delta = baseline - current
230		}
231		return ComparisonResult{
232			Baseline:  baseline,
233			Delta:     delta,
234			Direction: direction,
235		}
236	}
