198	func metricRecordFromExec(metricID string, rec ddxexec.RunRecord) metric.HistoryRecord {
199		out := metric.HistoryRecord{
200			RunID:        rec.RunID,
201			MetricID:     metricID,
202			DefinitionID: rec.DefinitionID,
203			ObservedAt:   rec.StartedAt,
204			Status:       metric.StatusPass,
205			ExitCode:     rec.ExitCode,
206			DurationMS:   rec.FinishedAt.Sub(rec.StartedAt).Milliseconds(),
207			Stdout:       rec.Result.Stdout,
208			Stderr:       rec.Result.Stderr,
209			ArtifactID:   metricID,
210		}
211		if rec.Status != ddxexec.StatusSuccess {
212			out.Status = metric.StatusFail
213		}
214		if rec.Result.Metric != nil {
215			out.Value = rec.Result.Metric.Value
216			out.Unit = rec.Result.Metric.Unit
217			out.Comparison = metric.ComparisonResult{
218				Baseline:  rec.Result.Metric.Comparison.Baseline,
219				Delta:     rec.Result.Metric.Comparison.Delta,
220				Direction: rec.Result.Metric.Comparison.Direction,
221			}
222		}
223		return out
224	}
