226	func compareMetricHistory(history []metric.HistoryRecord, against string) (metric.HistoryRecord, metric.ComparisonResult, error) {
227		if len(history) == 0 {
228			return metric.HistoryRecord{}, metric.ComparisonResult{}, fmt.Errorf("no history for metric")
229		}
230		current := history[len(history)-1]
231		target, err := selectMetricComparisonTarget(history, against)
232		if err != nil {
233			return metric.HistoryRecord{}, metric.ComparisonResult{}, err
234		}
235		direction := current.Comparison.Direction
236		if direction == "" {
237			direction = metric.ComparisonLowerIsBetter
238		}
239		result := metricComparisonFor(current.Value, target.Value, direction)
240		current.Comparison = result
241		return current, result, nil
242	}
243	
244	func selectMetricComparisonTarget(history []metric.HistoryRecord, against string) (metric.HistoryRecord, error) {
245		switch against {
246		case "", "latest":
247			return history[len(history)-1], nil
248		case "baseline":
249			return history[0], nil
250		default:
251			for _, rec := range history {
252				if rec.RunID == against {
253					return rec, nil
254				}
255			}
256			return metric.HistoryRecord{}, fmt.Errorf("comparison target %q not found", against)
257		}
258	}
259	
260	func trendMetricHistory(metricID string, history []metric.HistoryRecord) metric.TrendSummary {
261		if len(history) == 0 {
262			return metric.TrendSummary{MetricID: metricID}
263		}
264		summary := metric.TrendSummary{
265			MetricID:  metricID,
266			Min:       history[0].Value,
267			Max:       history[0].Value,
268			Latest:    history[len(history)-1].Value,
269			Unit:      history[len(history)-1].Unit,
270			UpdatedAt: history[len(history)-1].ObservedAt,
271		}
272		var sum float64
273		for _, rec := range history {
274			if rec.Value < summary.Min {
275				summary.Min = rec.Value
276			}
277			if rec.Value > summary.Max {
278				summary.Max = rec.Value
279			}
280			sum += rec.Value
281			summary.UpdatedAt = rec.ObservedAt
282			if rec.Unit != "" {
283				summary.Unit = rec.Unit
284			}
285		}
286		summary.Count = len(history)
287		summary.Average = sum / float64(len(history))
288		return summary
289	}
290	
291	func metricComparisonFor(current, baseline float64, direction string) metric.ComparisonResult {
292		delta := current - baseline
293		if direction == metric.ComparisonHigherIsBetter {
294			delta = baseline - current
295		}
296		return metric.ComparisonResult{
297			Baseline:  baseline,
298			Delta:     delta,
299			Direction: direction,
300		}
301	}
