105	func (f *CommandFactory) newBeadMetricsCommand() *cobra.Command {
106		cmd := &cobra.Command{
107			Use:   "metrics",
108			Short: "Per-bead cost, token, and attempt summaries from execution evidence",
109			Long: `Scan .ddx/executions/*/result.json and aggregate per-bead execution cost,
110	tokens, attempts, and average duration. One row per bead_id with recorded
111	execution evidence.`,
112			Args: cobra.NoArgs,
113			RunE: func(cmd *cobra.Command, args []string) error {
114				jsonOut, _ := cmd.Flags().GetBool("json")
115	
116				workspaceRoot := f.beadWorkspaceRoot()
117				if workspaceRoot == "" {
118					workspaceRoot = f.WorkingDir
119				}
120	
121				summaries, err := scanBeadMetrics(workspaceRoot)
122				if err != nil {
123					return err
124				}
125	
126				titleByID := map[string]string{}
127				if store := f.beadStore(); store != nil {
128					if all, err := store.List("", "", nil); err == nil {
129						for _, b := range all {
130							titleByID[b.ID] = b.Title
131						}
132					}
133				}
134	
135				rows := make([]beadMetricsRow, 0, len(summaries))
136				for id, s := range summaries {
137					rows = append(rows, beadMetricsRow{
138						BeadID:        id,
139						Title:         titleByID[id],
140						AttemptCount:  s.AttemptCount,
141						TotalTokens:   s.TotalTokens,
142						TotalCostUSD:  s.TotalCostUSD,
143						AvgDurationMS: s.AvgDurationMS,
144					})
145				}
146				sort.Slice(rows, func(i, j int) bool { return rows[i].BeadID < rows[j].BeadID })
147	
148				if jsonOut {
149					enc := json.NewEncoder(cmd.OutOrStdout())
150					enc.SetIndent("", "  ")
151					return enc.Encode(rows)
152				}
153				return renderBeadMetricsTable(cmd, rows)
154			},
155		}
156		cmd.Flags().Bool("json", false, "Output JSON")
157		return cmd
158	}
159	
160	func renderBeadMetricsTable(cmd *cobra.Command, rows []beadMetricsRow) error {
161		out := cmd.OutOrStdout()
162		fmt.Fprintf(out, "%-20s  %8s  %12s  %12s  %14s  %s\n",
163			"BEAD_ID", "ATTEMPTS", "TOTAL_TOKENS", "TOTAL_COST_USD", "AVG_DURATION_MS", "TITLE")
164		for _, r := range rows {
165			fmt.Fprintf(out, "%-20s  %8d  %12d  %12s  %14.1f  %s\n",
166				r.BeadID,
167				r.AttemptCount,
168				r.TotalTokens,
169				fmt.Sprintf("%.4f", r.TotalCostUSD),
170				r.AvgDurationMS,
171				r.Title,
172			)
173		}
174		return nil
175	}
