10		return ddxexec.Definition{
11			ID:          def.DefinitionID,
12			ArtifactIDs: []string{def.MetricID},
13			Executor: ddxexec.ExecutorSpec{
14				Kind:    ddxexec.ExecutorKindCommand,
15				Command: append([]string{}, def.Command...),
16				Cwd:     def.Cwd,
17				Env:     cloneStringMap(def.Env),
18			},
19			Result: ddxexec.ResultSpec{
20				Metric: &ddxexec.MetricResultSpec{
21					Unit: def.Thresholds.Unit,
22				},
23			},
24			Evaluation: ddxexec.Evaluation{
25				Comparison: def.Comparison,
26				Thresholds: ddxexec.Thresholds{
27					WarnMS:    def.Thresholds.Warn,
28					RatchetMS: def.Thresholds.Ratchet,
29				},
30			},
31			Active:    def.Active,
32			CreatedAt: def.CreatedAt,
33		}
34	}
