36	func metricDefinitionFromExec(def ddxexec.Definition) (Definition, error) {
37		metricID := ""
38		if len(def.ArtifactIDs) > 0 {
39			metricID = def.ArtifactIDs[0]
40		}
41		out := Definition{
42			DefinitionID: def.ID,
43			MetricID:     metricID,
44			Command:      append([]string{}, def.Executor.Command...),
45			Cwd:          def.Executor.Cwd,
46			Env:          cloneStringMap(def.Executor.Env),
47			Thresholds: Thresholds{
48				Warn:    def.Evaluation.Thresholds.WarnMS,
49				Ratchet: def.Evaluation.Thresholds.RatchetMS,
50				Unit:    "",
51			},
52			Comparison: def.Evaluation.Comparison,
53			Active:     def.Active,
54			CreatedAt:  def.CreatedAt,
55		}
56		if def.Result.Metric != nil {
57			out.Thresholds.Unit = def.Result.Metric.Unit
58		}
59		return out, nil
60	}
