62	func metricHistoryToRun(rec HistoryRecord) ddxexec.RunRecord {
63		startedAt := rec.ObservedAt
64		finishedAt := rec.ObservedAt
65		if rec.DurationMS > 0 {
66			finishedAt = rec.ObservedAt.Add(time.Duration(rec.DurationMS) * time.Millisecond)
67		}
68		status := ddxexec.StatusFailed
69		switch rec.Status {
70		case StatusPass:
71			status = ddxexec.StatusSuccess
72		case StatusFail:
73			status = ddxexec.StatusFailed
74		}
75		manifest := ddxexec.RunManifest{
76			RunID:        rec.RunID,
77			DefinitionID: rec.DefinitionID,
78			ArtifactIDs:  []string{rec.MetricID},
79			StartedAt:    startedAt,
80			FinishedAt:   finishedAt,
81			Status:       status,
82			ExitCode:     rec.ExitCode,
83			Provenance:   ddxexec.Provenance{},
84		}
85		runResult := ddxexec.RunResult{
86			Stdout: rec.Stdout,
87			Stderr: rec.Stderr,
88			Value:  rec.Value,
89			Unit:   rec.Unit,
90			Parsed: true,
91		}
92		if rec.Comparison.Direction != "" || rec.Comparison.Baseline != 0 || rec.Comparison.Delta != 0 {
93			runResult.Metric = &ddxexec.MetricObservation{
94				ArtifactID:   rec.MetricID,
95				DefinitionID: rec.DefinitionID,
96				ObservedAt:   rec.ObservedAt,
97				Status:       rec.Status,
98				Value:        rec.Value,
99				Unit:         rec.Unit,
100				Samples:      []float64{rec.Value},
101				Comparison: ddxexec.ComparisonResult{
102					Baseline:  rec.Comparison.Baseline,
103					Delta:     rec.Comparison.Delta,
104					Direction: rec.Comparison.Direction,
105				},
106			}
107		}
108		return ddxexec.RunRecord{
109			RunManifest: manifest,
110			Result:      runResult,
111		}
112	}
113	
114	func metricHistoryFromExec(rec ddxexec.RunRecord) (HistoryRecord, error) {
115		out := HistoryRecord{
116			RunID:        rec.RunID,
117			MetricID:     firstArtifactID(rec.ArtifactIDs),
118			DefinitionID: rec.DefinitionID,
119			ObservedAt:   rec.StartedAt,
120			Status:       StatusPass,
121			ExitCode:     rec.ExitCode,
122			DurationMS:   rec.FinishedAt.Sub(rec.StartedAt).Milliseconds(),
123			Stdout:       rec.Result.Stdout,
124			Stderr:       rec.Result.Stderr,
125			ArtifactID:   firstArtifactID(rec.ArtifactIDs),
126		}
127		if rec.Status != ddxexec.StatusSuccess {
128			out.Status = StatusFail
129		}
130		if rec.Result.Metric != nil {
131			out.Value = rec.Result.Metric.Value
132			out.Unit = rec.Result.Metric.Unit
133			out.Comparison = ComparisonResult{
134				Baseline:  rec.Result.Metric.Comparison.Baseline,
135				Delta:     rec.Result.Metric.Comparison.Delta,
136				Direction: rec.Result.Metric.Comparison.Direction,
137			}
138		}
139		return out, nil
140	}
