142	func cloneStringMap(in map[string]string) map[string]string {
143		if len(in) == 0 {
144			return nil
145		}
146		out := make(map[string]string, len(in))
147		for k, v := range in {
148			out[k] = v
149		}
150		return out
151	}
152	
153	func firstArtifactID(ids []string) string {
154		if len(ids) == 0 {
155			return ""
156		}
157		return ids[0]
158	}
