33	func (s *Store) Validate(metricID string) (*Definition, *docgraph.Document, error) {
34		doc, err := s.loadMetricArtifact(metricID)
35		if err != nil {
36			return nil, nil, err
37		}
38		def, err := s.LoadDefinition(metricID)
39		if err != nil {
40			return nil, nil, err
41		}
42		if def.MetricID != metricID {
43			return nil, nil, fmt.Errorf("metric definition %q does not target %q", def.DefinitionID, metricID)
44		}
45		if len(def.Command) == 0 {
46			return nil, nil, fmt.Errorf("metric definition %q has no command", def.DefinitionID)
47		}
48		if def.Comparison == "" {
49			def.Comparison = ComparisonLowerIsBetter
50		}
51		switch def.Comparison {
52		case ComparisonLowerIsBetter, ComparisonHigherIsBetter:
53		default:
54			return nil, nil, fmt.Errorf("metric definition %q has invalid comparison %q", def.DefinitionID, def.Comparison)
55		}
56		return &def, doc, nil
57	}
